insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch1-l1-s1', 'itf-f-ch1-l1', 'itf-f-ch1-l1-milestone', 1, 'Every technology serves a purpose', 'discussion', 'intro', 'Technology is any tool or machine that is made to serve a purpose. Each is used to perform a particular task; each serves a specific purpose. In Example 1.1, the hammer and screwdriver both help us build, but one hammers in nails while the other drives in screws. A bus and a car both provide transportation, but a bus transports many people and a car transports few. A space shuttle and an airplane both fly people and cargo, but the shuttle flies them to space while the airplane flies them to locations on the ground.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['process.purpose']::text[], 1, 'explanation', null)
on conflict (id) do update set
  lesson_id = excluded.lesson_id,
  milestone_id = excluded.milestone_id,
