  mode_type = excluded.mode_type;

insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch1-l1-s2', 'itf-f-ch1-l1', 'itf-f-ch1-l1-milestone', 2, 'General-purpose personal computers', 'discussion', 'teach', 'The computer is also a technology. The four types of personal computer are the desktop, laptop, tablet, and smartphone. They are general-purpose technologies because they serve more than one purpose. Example 1.2 shows those purposes: entertainment such as reading e-books, playing games, and watching videos; work such as attending online classes, finding information, doing homework, reviewing patient records, preparing lessons, and creating digital artwork; and communication with friends, family, teachers, and classmates.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['process.purpose', 'itf.computers.categories']::text[], 1, 'explanation', null)
on conflict (id) do update set
  lesson_id = excluded.lesson_id,
  milestone_id = excluded.milestone_id,
