insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch1-l1-s3', 'itf-f-ch1-l1', 'itf-f-ch1-l1-milestone', 3, 'Three specific-purpose categories', 'discussion', 'teach', 'Embedded computers, servers, and supercomputers are specific-purpose computers. Embedded computers sit inside machines and control them, so they are often called control modules. In Example 1.3, an elevator''s embedded computer senses a pressed button, moves to that floor, and controls its doors; in Example 1.4, a car''s engine control module controls the engine and its brake control module controls the brakes. A server serves requests from many clients at the same time: Example 1.5 describes YouTube video requests, Amazon buying and selling requests, and Google information requests. A supercomputer responds to one big request rather than many small ones; Example 1.6 uses the many calculations needed to predict the weather. The four main computer categories are embedded computers, personal computers, servers, and supercomputers.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['process.purpose', 'itf.computers.categories']::text[], 1, 'explanation', null)
