values ('itf-f-ch1-l1-s4', 'itf-f-ch1-l1', 'itf-f-ch1-l1-milestone', 4, 'Your own purposes', 'reflection', 'practice', 'First list two tasks, not mentioned in the lesson, that a personal computer can perform. Then name three additional technologies that were not mentioned and state the specific purpose for which each one is made. Explain each purpose in your own words.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['process.purpose']::text[], 1, 'reflection', null)
