values ('itf-f-ch1-l1-s5', 'itf-f-ch1-l1', 'itf-f-ch1-l1-milestone', 5, 'Match technologies to purposes', 'multiple_choice', 'assessment', 'Which option matches every technology with the specific purpose given in the book''s matching activity?', 'multiple_choice', '', null, '[{"id": "a", "text": "Hammer—hammering in nails; bus—transporting many people; space shuttle—flying people to space; telescope—looking at distant objects; elevator—moving people up and down in a building; server—serving small requests from many clients; supercomputer—solving big problems."}, {"id": "b", "text": "Hammer—looking at distant objects; bus—transporting many people; space shuttle—flying people to space; telescope—hammering in nails; elevator—moving people up and down in a building; server—serving small requests from many clients; supercomputer—solving big problems."}, {"id": "c", "text": "Hammer—hammering in nails; bus—transporting few people; space shuttle—flying between locations on the ground; telescope—looking at distant objects; elevator—moving people up and down in a building; server—solving one big problem; supercomputer—serving many clients."}, {"id": "d", "text": "Hammer—driving in screws; bus—transporting many people; space shuttle—flying people to space; telescope—looking at distant objects; elevator—serving small client requests; server—moving people between floors; supercomputer—solving big problems."}]'::jsonb, '{}'::jsonb, ARRAY['process.purpose']::text[], 1, 'assessment', 'mcq')
