insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch1-l2-s1', 'itf-f-ch1-l2', 'itf-f-ch1-l2-milestone', 1, 'Parts working as one system', 'discussion', 'intro', 'A system is something that is made up of parts working together as one whole unit. To serve its purpose, a system must do work, and that work results in change. Example 2.1 shows a bicycle changing pressure on a pedal into the spinning of its rear wheel. In Example 2.2, a computer changes pressure on keyboard keys into letters on a screen. Example 2.3 shows that a living thing can also be a system: the human body changes the sound of a question into the sound of an answer.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['systems.process']::text[], 1, 'explanation', null)
on conflict (id) do update set
  lesson_id = excluded.lesson_id,
  milestone_id = excluded.milestone_id,
  position = excluded.position,
  title = excluded.title,
  activity_type = excluded.activity_type,
  stage = excluded.stage,
  prompt = excluded.prompt,
  response_mode = excluded.response_mode,
  starter_code = excluded.starter_code,
  expected_output = excluded.expected_output,
  choices = excluded.choices,
  rubric = excluded.rubric,
  skill_keys = excluded.skill_keys,
  pass_score = excluded.pass_score,
  mode = excluded.mode,
  mode_type = excluded.mode_type;

insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch1-l2-s2', 'itf-f-ch1-l2', 'itf-f-ch1-l2-milestone', 2, 'Signals, input, and output', 'discussion', 'teach', 'A signal is a message that is carried in physical form. Example 2.4 shows a question carried by sound to an ear, the word "Hello" carried by light to an eye, and letter names carried by pressure to a keyboard. A system that works with signals must capture and emit them. Capturing is input: microphones capture sound, cameras capture light, and mice, keyboards, touchpads, and digitizers capture pressure. Emitting is output: speakers emit sound, screens emit light, and vibration motors exert pressure. The human body inputs through ears, eyes, and skin, then outputs through actions of the mouth, arms, and legs.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['systems.input', 'systems.output', 'itf.signals.types']::text[], 1, 'explanation', null)
on conflict (id) do update set
