insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch1-l2-s3', 'itf-f-ch1-l2', 'itf-f-ch1-l2-milestone', 3, 'Input and output in an elevator', 'discussion', 'teach', 'An embedded computer''s input and output devices depend on the machine it controls. Input panels accept keys, buttons, and dials; sensors capture particular forms, such as heat sensors sensing temperature and infrared sensors sensing infrared light. In Example 2.5, Alan presses 6 on the elevator''s cabin operating panel. In Example 2.6, an infrared sensor receives light across the doorway; if a body blocks that signal, the computer keeps the doors open. Example 2.7 shows a screen displaying the floor and speakers beeping on arrival. Embedded computers also use output devices called actuators. In Example 2.8, a small motor pushes or pulls the doors and a large motor moves the cabin. Actuator output is commonly pressure that causes a push or pull and results in action.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['systems.input', 'systems.output', 'itf.signals.types']::text[], 1, 'explanation', null)
