insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch1-l3-s1', 'itf-f-ch1-l3', 'itf-f-ch1-l3-milestone', 1, 'Translate signals for the processor', 'discussion', 'intro', 'Changing input signals to output signals is called processing, and it happens inside a computer in a part called the processor. Because the processor works on electricity, it understands only electronic signals—not the sound, light, and pressure signals of the outside world. Translation means changing a message from one language into another without changing its meaning. Input devices translate outside-world signals into electronic signals; output devices translate electronic signals back into outside-world signals. Each input or output device is specialized to translate a particular form of signal.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['signals.conversion', 'systems.process']::text[], 1, 'explanation', null)
on conflict (id) do update set
  lesson_id = excluded.lesson_id,
