insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch1-l3-s2', 'itf-f-ch1-l3', 'itf-f-ch1-l3-milestone', 2, 'The interface and the processor', 'discussion', 'teach', 'The interface is the boundary between the outside world and the inside world of a computer, where signals are translated. All input and output devices form the user interface; the auditory interface translates sound and the visual interface translates light. All computer parts are called hardware. The processor is the hardware that changes input to output, so it is the computer''s central processing unit. In Example 3.1, Karl says, "Hey Siri!" The microphone translates that sound into electronic signals; the processor wakes Siri and sends an electronic message to the speaker; the speaker translates it into the sound "How can I help you?"', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['signals.conversion', 'systems.process']::text[], 1, 'explanation', null)
