insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch1-l3-s3', 'itf-f-ch1-l3', 'itf-f-ch1-l3-milestone', 3, 'Humans and embedded computers process signals', 'discussion', 'teach', 'Humans have a brain instead of a processor. The brain also works with electricity, using action potential signals. Ears, eyes, and skin translate outside signals into action potentials, while the mouth, arms, and legs translate action potentials into sound or movement. Embedded computers use electronic signals and have input and output devices suited to their machines; actuators translate electronic signals into movement. In Example 3.2, an elevator''s operating panel and call button translate user input into electronic signals. The control module processes them, then makes the doors close and the cabin move; its screen and speakers can also produce output.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['signals.conversion', 'systems.process']::text[], 1, 'explanation', null)
