insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch1-l3-s4', 'itf-f-ch1-l3', 'itf-f-ch1-l3-milestone', 4, 'Trace five signal paths', 'reflection', 'practice', 'Write each path in order from input device, through the processor, to output device or actuator: (a) taking a friend''s picture so it appears on the screen; (b) saying "Hey Siri" and hearing "How can I help you?"; (c) clicking a mouse so an app starts on the screen; (d) touching a touchscreen so a video starts playing on its screen and speaker; and (e) pressing an elevator floor button so the doors close and the cabin moves up. Name every device in each path.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['signals.conversion', 'systems.process']::text[], 1, 'reflection', null)
