insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch1-l3-s5', 'itf-f-ch1-l3', 'itf-f-ch1-l3-milestone', 5, 'Identify signal translators', 'reflection', 'practice', 'Complete these identifications using the lesson''s device and body-part names. Name the two parts of the visual interface, the two parts of the auditory interface, and the two parts of a touchscreen. State which two stages—input or output—involve translation, which two human limbs perform an actuator-like function, and which two elevator parts have motors and are actuators. Using ear, camera, digitizer, screen, skin, and microphone once each, match these translations: sound to electronic signals; sound to action potentials; electronic to light; pressure to electronic; pressure to action potentials; light to electronic. Then use operating panel, infrared sensor, hand, mechanized cabin, mouth, and actuator once each for: pressure to electronic; infrared to electronic; action potentials to a hand movement; electronic signals to cabin movement; action potentials to sound; electronic signals to any movement.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['signals.conversion', 'systems.process']::text[], 1, 'reflection', null)
