values ('itf-f-ch1-l3-s6', 'itf-f-ch1-l3', 'itf-f-ch1-l3-milestone', 6, 'Check translation and processing', 'multiple_choice', 'assessment', 'Which summary is fully correct?', 'multiple_choice', '', null, '[{"id": "a", "text": "A processor changes input to output and works with electronic signals. Input devices translate outside-world signals into electronic signals; output devices translate electronic signals outward; actuators translate electronic signals into movement. Embedded computers have processors, and translation happens at the interface."}, {"id": "b", "text": "A processor works only with light signals. Input devices translate electronic signals outward, while output devices cannot translate. Embedded computers do not have processors."}, {"id": "c", "text": "A processor captures every outside-world signal directly. An actuator is an input device, and the interface is located only inside the processor."}, {"id": "d", "text": "Processing happens outside the computer. The interface prevents translation, and a processor changes output back into input without using electronic signals."}]'::jsonb, '{}'::jsonb, ARRAY['signals.conversion', 'systems.process']::text[], 1, 'assessment', 'mcq')
