insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch1-l4-s1', 'itf-f-ch1-l4', 'itf-f-ch1-l4-milestone', 1, 'A holding place for signals', 'discussion', 'intro', 'Memory is the holding place of signals inside a computer. Input electronic signals wait there to be processed, and processed electronic signals wait there to become output. The memory module is the hardware dedicated to main memory, and its capacity limits how many signals it can hold. In Example 4.1, Leena''s tiny computer has only six places in memory. When all six are full, a new input signal has nowhere to go and must be dropped; the computer can accept it only after a place becomes available. If a memory module is too small, the system slows while it waits for room.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['memory.storage']::text[], 1, 'explanation', null)
