insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch1-l4-s2', 'itf-f-ch1-l4', 'itf-f-ch1-l4-milestone', 2, 'Main memory works with storage', 'discussion', 'teach', 'Storage is a form of memory, but it is much larger than main memory. Signals that need to stay in the computer but do not need processing are sent to storage, freeing main memory for signals that do need processing. In Example 4.2, Leena takes a photograph. The camera translates light into electronic signals and sends them to main memory; a copy is processed, placed back in main memory, and sent to the screen so she can see it. When she saves the photograph, a copy of its signals is sent from main memory to storage before she powers off the smartphone.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['memory.storage']::text[], 1, 'explanation', null)
