insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch1-l5-s1', 'itf-f-ch1-l5', 'itf-f-ch1-l5-milestone', 1, 'Exchange signals across an interface', 'discussion', 'intro', 'Systems can exchange signals across an interface. Two conditions must be satisfied: signals must be able to travel between the systems, and both systems must be able to translate the signals sent back and forth. The human-computer interface, also called the user interface, lets humans and computers exchange sound, light, and pressure signals even though humans think with action potentials and computers process electronic signals. In the book''s misnumbered Example 4.1, Sarah presses her tablet touchscreen; pressure becomes electronic input, the video starts, and its light and sound travel back to her eyes and ears and become action potentials.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['signals.exchange', 'systems.output']::text[], 1, 'explanation', null)
