insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch1-l5-s2', 'itf-f-ch1-l5', 'itf-f-ch1-l5-milestone', 2, 'Radio waves and Bluetooth', 'discussion', 'teach', 'Computers can exchange radio waves, which travel in all directions and can be sensed and emitted by computers but not by humans. An antenna is both an input and output device: it translates radio waves to electronic signals and electronic signals to radio waves. Bluetooth carries signals over short distances, up to about 10 meters. In Example 4.2, Sarah sends a photograph from smartphone to desktop; the phone sends a copied signal as radio waves and the desktop translates it back. Examples 4.3, 4.4, and 4.5 show her phone exchanging Bluetooth signals with embedded computers in earphones, a smart television, and a car so music or video can play through those devices.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['signals.exchange', 'systems.output']::text[], 1, 'explanation', null)
