insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch1-l5-s3', 'itf-f-ch1-l5', 'itf-f-ch1-l5-milestone', 3, 'The Internet bridges long distances', 'discussion', 'teach', 'The Internet is a large system whose parts carry signals between computers across long distances. WiFi is found in all four personal-computer types; its antennas exchange radio waves with a gateway device across about 100 meters. Cellular antennas exchange radio waves with a cell tower across about 1,000 meters and are found only in smartphones and a few select tablets. Gateway devices and cell towers are Internet access points. Network cables carry network electronic signals, and a network port translates between those signals and the internal electronic signals arranged differently inside a computer. Wired interfaces use cables and electronic signals; wireless interfaces use antennas and radio waves through the air. In Example 4.6, Sarah is away from her home gateway, so she requests a YouTube video through a cellular tower. The Internet delivers the request to a server through a wired interface; the server copies the video''s stored signals and returns them through the Internet and tower to her smartphone.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['signals.exchange', 'systems.output']::text[], 1, 'explanation', null)
