insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch1-l5-s4', 'itf-f-ch1-l5', 'itf-f-ch1-l5-milestone', 4, 'Choose systems and wireless technologies', 'reflection', 'practice', 'Classify each exchange as personal-computer with server through the Internet, personal-computer with personal-computer, or personal-computer with embedded-computer: playing phone music through car speakers; using a tablet to search Google; sending a tablet photograph to a desktop; showing a tablet movie on a smart television; watching YouTube on a laptop. Then rank Bluetooth, WiFi, and cellular from shortest to longest useful distance. Finally name the wireless technology or technologies that fit each case: phone-to-laptop photograph transfer; desktop watching YouTube; smartphone watching YouTube; laptop searching Google; laptop playing music through earphones.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['signals.exchange']::text[], 1, 'reflection', null)
