insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch1-l5-s5', 'itf-f-ch1-l5', 'itf-f-ch1-l5-milestone', 5, 'Trace a YouTube exchange', 'reflection', 'practice', 'Answer the interface questions in two parts. First name the human-computer interface; state the two conditions needed for two systems to exchange signals; explain why the Internet is a system and its purpose; name its two access-point devices and which one can provide wired and wireless access; and state what signals antennas and network ports exchange and what those signals travel through. Then trace this case: "I watched a YouTube video on my smartphone while going to the mall in the car." Identify Computer 1 and Computer 2, the wired and wireless interfaces, each access point, and the signal form that bridges each interface.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['signals.exchange', 'systems.output']::text[], 1, 'reflection', null)
