insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch1-l5-s6', 'itf-f-ch1-l5', 'itf-f-ch1-l5-milestone', 6, 'Check interfaces and access points', 'multiple_choice', 'assessment', 'Which summary is fully correct?', 'multiple_choice', '', null, '[{"id": "a", "text": "Two systems can exchange signals when signals can travel between them and both can translate them; this includes humans with computers and personal computers with embedded computers. Computers exchange copies. The Internet is a system connecting personal computers with servers; gateway devices and cell towers are access points. Bluetooth and WiFi are wireless radio-wave technologies, a gateway can provide wired and wireless access, and WiFi and cellular can interface with the Internet. Wired interfaces use cables and electronic signals; wireless interfaces use antennas and radio waves. Cellular antennas are found in smartphones and some tablets."}, {"id": "b", "text": "Signals do not need to travel across an interface. Computers exchange their only original signals. Bluetooth is wired, and neither gateway devices nor cell towers provide Internet access."}, {"id": "c", "text": "Humans cannot exchange signals with computers. Embedded computers cannot exchange with personal computers. WiFi uses network cables only, and cellular is used only for direct Bluetooth transfers."}, {"id": "d", "text": "The Internet is not a system. A gateway device can provide only a wired interface, while cell towers exchange signals through network cables with every desktop and laptop."}]'::jsonb, '{}'::jsonb, ARRAY['signals.exchange', 'systems.output']::text[], 1, 'assessment', 'mcq')
