insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch2-l1-s1', 'itf-f-ch2-l1', 'itf-f-ch2-l1-milestone', 1, 'From input to output', 'discussion', 'intro', 'Performance refers to how fast a computer works. More specifically, it is the speed of processing: how quickly the computer changes input to output. The processor is the part of the computer where input is changed to output. Every input-output cycle is initiated by the clock. As Example 1.1 shows, a CPU contains a processor and a clock; input signals wait until the clock sends a "Go" signal before entering the processor.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['itf.hardware.performance']::text[], 1, 'explanation', null)
on conflict (id) do update set
  lesson_id = excluded.lesson_id,
  milestone_id = excluded.milestone_id,
  position = excluded.position,
