values ('itf-f-ch2-l1-s6', 'itf-f-ch2-l1', 'itf-f-ch2-l1-milestone', 6, 'Check performance facts', 'multiple_choice', 'assessment', 'Select every statement that is true.', 'multiple_choice', '', null, '[{"id": "a", "text": "Performance means how fast a computer works."}, {"id": "b", "text": "The CPU clock signals when each input-output cycle begins."}, {"id": "c", "text": "The CPU clock tells you the time."}, {"id": "d", "text": "Processor performance does not affect computer performance."}, {"id": "e", "text": "Making the clock rate faster is one way to improve performance."}, {"id": "f", "text": "Adding processors makes performance worse."}, {"id": "g", "text": "At the same clock rate, four cores should be faster than one core."}, {"id": "h", "text": "With the same core count, 4 GHz should be faster than 3 GHz."}]'::jsonb, '{}'::jsonb, ARRAY['itf.hardware.performance']::text[], 1, 'assessment', 'mcq')
