values ('itf-f-ch2-l1-s7', 'itf-f-ch2-l1', 'itf-f-ch2-l1-milestone', 7, 'Identify CPU specifications', 'multiple_choice', 'assessment', 'Three groups show numbered CPUs. Group (a): [1] single-core at 3 GHz, [2] dual-core at 1 GHz, [3] quad-core at 2 GHz. Group (b): [1] single-core at 1 GHz, [2] dual-core at 4 GHz, [3] single-core at 4 GHz. Group (c): [1] dual-core at 2 GHz, [2] quad-core at 2 GHz, [3] quad-core at 4 GHz. Which option-number sequence identifies, in order, (a) dual-core at 1 GHz, (b) single-core at 4 GHz, and (c) quad-core at 2 GHz?', 'multiple_choice', '', null, '[{"id": "a", "text": "2, 3, 2"}, {"id": "b", "text": "1, 2, 1"}, {"id": "c", "text": "3, 1, 3"}, {"id": "d", "text": "2, 2, 3"}]'::jsonb, '{}'::jsonb, ARRAY['itf.hardware.performance']::text[], 1, 'assessment', 'mcq')
