insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch2-l2-s1', 'itf-f-ch2-l2', 'itf-f-ch2-l2-milestone', 1, 'Getting electrical energy', 'discussion', 'intro', 'A system needs energy to do work, and a computer needs electrical energy. As Example 2.1 shows, electrical outlets may differ in shape, but they all deliver electrical energy to devices and machines. A computer can use that energy directly or store it for later. The battery is the hardware part responsible for storing electrical energy. Laptops, tablets, and smartphones can charge their batteries and later disconnect from the outlet. A desktop has no battery and must remain connected to an outlet.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['itf.hardware.energy']::text[], 1, 'explanation', null)
