insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch2-l2-s2', 'itf-f-ch2-l2', 'itf-f-ch2-l2-milestone', 2, 'Screens use energy', 'discussion', 'teach', 'Every hardware part uses electrical energy, but the screen and processor use a lot. A screen converts electronic signals into light signals. The more light it must give out, the more electrical energy it uses. Example 2.2 compares screen sizes: a big screen gives out more light and uses more electrical energy than a small screen. Example 2.3 compares brightness: a bright screen gives out more light and uses more electrical energy than a dim screen.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['itf.hardware.energy']::text[], 1, 'explanation', null)
on conflict (id) do update set
  lesson_id = excluded.lesson_id,
  milestone_id = excluded.milestone_id,
  position = excluded.position,
  title = excluded.title,
  activity_type = excluded.activity_type,
