insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch2-l2-s3', 'itf-f-ch2-l2', 'itf-f-ch2-l2-milestone', 3, 'Processors use energy', 'discussion', 'teach', 'The processor changes input into output. The more signals it processes, the more electrical energy it uses. In general, a faster processor requires more energy. Example 2.4 compares clock rates: a faster clock rate processes more signals and uses more electrical energy. Example 2.5 compares core counts: a CPU with more cores processes more signals and uses more electrical energy. The book summarizes this trade-off by saying that the price of performance is energy consumption.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['itf.hardware.energy']::text[], 1, 'explanation', null)
