insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch2-l2-s4', 'itf-f-ch2-l2', 'itf-f-ch2-l2-milestone', 4, 'Compare screen energy', 'reflection', 'practice', 'Make two controlled comparisons from Activities 2.2 and 2.4. First assume the same brightness and compare a desktop, laptop, tablet, and smartphone screen: identify which uses the most and least electrical energy and explain how screen size leads to your answer. Then assume the same screen size and compare dim, bright, and brightest settings: identify which uses the most and least energy and explain how the amount of light leads to your answer.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['itf.hardware.energy']::text[], 1, 'reflection', null)
