insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch2-l3-s1', 'itf-f-ch2-l3', 'itf-f-ch2-l3-milestone', 1, 'Portable energy', 'discussion', 'intro', 'A portable device can be easily carried around while it is being used. Its portability depends on three features: source of energy, size, and weight. A working computer must remain connected to its direct source of electrical energy. For a desktop, that source is the outlet; pulling out its power cable turns it off. For a laptop, tablet, or smartphone, the battery is the direct source. A battery stores electrical energy and is itself portable, allowing the computer to be carried while it works.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['itf.hardware.portability']::text[], 1, 'explanation', null)
on conflict (id) do update set
  lesson_id = excluded.lesson_id,
