insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch2-l3-s2', 'itf-f-ch2-l3', 'itf-f-ch2-l3-milestone', 2, 'Size and weight', 'discussion', 'teach', 'A portable computer should be easy to carry, so size and weight matter. The desktop is too big and heavy to be portable and is a stationary computer. The laptop is smaller and can be placed on a lap. Tablets and smartphones are smaller and lighter still and can be held in one hand. Battery size follows computer size: a laptop can fit the largest battery of these portable types, while a smartphone can fit the smallest.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['itf.hardware.portability']::text[], 1, 'explanation', null)
on conflict (id) do update set
  lesson_id = excluded.lesson_id,
