insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch2-l3-s3', 'itf-f-ch2-l3', 'itf-f-ch2-l3-milestone', 3, 'The user interface changes', 'discussion', 'teach', 'The user interface is the sum of a computer''s input and output devices. As computers become smaller and lighter, those devices change too. A desktop uses a keyboard and mouse. A laptop also has a keyboard but uses a touchpad; its keyboard-and-touchpad combination is slightly smaller than the desktop''s keyboard-and-mouse combination. Tablets and smartphones replace those devices with a smaller, lighter touchscreen, changing interaction from pointing with a device to touching with a finger. Screens also shrink from desktop to laptop to tablet to smartphone. A smaller screen improves portability but fits less content and makes objects smaller.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['itf.hardware.portability']::text[], 1, 'explanation', null)
on conflict (id) do update set
  lesson_id = excluded.lesson_id,
