insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch2-l3-s4', 'itf-f-ch2-l3', 'itf-f-ch2-l3-milestone', 4, 'Portability changes energy demand', 'discussion', 'teach', 'Making a computer smaller requires a smaller battery, and a smaller battery stores less electrical energy. The computer must therefore use less energy if its battery is to last. A smaller screen gives out less light and uses less energy. In the book''s general comparison, a smaller computer also uses a less demanding CPU, usually with a slower clock rate and fewer cores. Larger computers demand more energy but have space for larger batteries that store more energy. The book notes that this CPU comparison is simplified and leaves out the complexities of balancing performance with power efficiency.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['itf.hardware.portability']::text[], 1, 'explanation', null)
