values ('itf-f-ch2-l3-s5', 'itf-f-ch2-l3', 'itf-f-ch2-l3-milestone', 5, 'Compare user interfaces', 'reflection', 'practice', 'Make the interface comparisons from Activities 3.3 and 3.4. Name one output-device feature that distinguishes a desktop from a smartphone. Name two input-device features that distinguish a laptop from a tablet. Then compare the laptop with the desktop: list the keyboard, pointing-device, and screen differences, and explain how having the laptop''s input and output devices attached as one unit—rather than detached like the desktop''s—affects portability.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['itf.hardware.portability']::text[], 1, 'reflection', null)
