insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch3-l1-s1', 'itf-f-ch3-l1', 'itf-f-ch3-l1-milestone', 1, 'Instructions move from input to output', 'discussion', 'intro', 'Instructions are action statements. Each instruction indicates a specific action that should be performed, and both humans and computers are systems capable of following instructions. An instruction enters a system as an input signal, is held in memory, and is followed by the processor to generate an output. Ms. Finn asked Sarah to multiply 2 and 3, add 4, and then divide by 2. Sarah had to remember the three instructions in order. She processed them one after another to reach 5, kept that answer in memory until Ms. Finn was ready, and then gave 5 as the output. When the rest of the class followed the same instructions in the same order, they reached the same result.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['logic.sequence', 'itf.software.instructions']::text[], 1, 'explanation', null)
