values ('itf-f-ch3-l1-s2', 'itf-f-ch3-l1', 'itf-f-ch3-l1-milestone', 2, 'Run Sarah''s ordered calculation', 'code', 'practice', 'The book presents Sarah''s calculation as three instructions. Run this valid Jargon version and trace how each result is used by the next instruction. The order must remain multiplication, addition, and division so that the final output is 5.', 'code', 'SET result (2 * 3)
SET result (result + 4)
SET result (result // 2)
PRINT result', '5', '[]'::jsonb, '{}'::jsonb, ARRAY['logic.sequence']::text[], 1, 'practice', 'code')
