insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch3-l1-s4', 'itf-f-ch3-l1', 'itf-f-ch3-l1-milestone', 4, 'Shared calls and flowcharts', 'discussion', 'teach', 'Instructions can be shared. One set may call and use another set, so common instructions can be kept on their own instead of copied into every task. When Chen''s getting-ready-for-school instructions say ''brush your teeth,'' that instruction calls the older set he memorized: put toothpaste on the toothbrush, brush the outer, inner, and chewing surfaces, then rinse. His getting-ready-for-sleep task calls the same set, so he does not memorize it again. A flowchart is a diagram that shows the steps required to complete a task. Shapes represent steps, and arrows show their order. In the getting-ready-for-school flowchart, terminator boxes mark Start and End, while process boxes carry the five task instructions.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['logic.sequence', 'itf.software.instructions']::text[], 1, 'explanation', null)
