insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch3-l1-s5', 'itf-f-ch3-l1', 'itf-f-ch3-l1-milestone', 5, 'Build and compare instruction sets', 'discussion', 'practice', 'Complete the lesson''s connected project. First extract action-verb instructions from the microwave and elevator narratives, avoiding the word ''the'' as the book advises. Activity 1.2 asks for five microwave instructions and Activity 1.3 asks for six elevator instructions, while the later templates provide seven READ/WRITE slots for each; preserve the printed requests and note this mismatch. Create the Word files ''Using Microwave Oven Instructions'' and ''Using Elevator Instructions,'' then answer where READ reads from, where WRITE writes to, how many of each instruction appear, and the save names. For each file, select all text; set size 20, Courier New, and Black, Text 1, Lighter 50%; number the lines; color each line''s first word RGB 255,0,255; save and close. Count the shared appendix calls, identify which main instructions make them, and explain how the shared ''How to'' section saves pages. In PowerPoint, make a blank portrait template with seven centered, vertically distributed process boxes, two terminator boxes, and connecting arrows; save it as ''Flowchart Template.'' Fill copies with Start, End, and the microwave or elevator instructions; save them as ''Using Microwave Oven Flowchart'' and ''Using Elevator Flowchart.'' Compare the common task and changed source or file in the three pairs from Activity 1.9.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['logic.sequence', 'itf.software.instructions']::text[], 1, 'assignment', null)
