values ('itf-f-ch3-l1-s6', 'itf-f-ch3-l1', 'itf-f-ch3-l1-milestone', 6, 'Check instruction facts', 'multiple_choice', 'assessment', 'Select every statement that is true.', 'multiple_choice', '', null, '[{"id": "a", "text": "An instruction is an action statement."}, {"id": "b", "text": "Computers cannot follow instructions."}, {"id": "c", "text": "Instructions enter a system as input."}, {"id": "d", "text": "All instructions are held in memory."}, {"id": "e", "text": "A set of instructions for a computer is called a program."}, {"id": "f", "text": "Each set of instructions is designed to perform a specific task."}, {"id": "g", "text": "A set of instructions may call on another set of instructions for help."}, {"id": "h", "text": "A set of instructions cannot be shared."}]'::jsonb, '{}'::jsonb, ARRAY['logic.sequence', 'itf.software.instructions']::text[], 1, 'assessment', 'mcq')
