insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch3-l2-s1', 'itf-f-ch3-l2', 'itf-f-ch3-l2-milestone', 1, 'User software and application size', 'discussion', 'intro', 'Software is the name given to all the programs in a computer. It is grouped by purpose: user software performs tasks for the user, system software performs tasks for the whole system, and firmware performs tasks for only the hardware. A user-software program is called an application or app, and each app has a specific task. On Sarah''s smartphone, the calculator multiplies numbers, the camera takes photographs, and the messaging app sends messages. Software size is determined by its number of instructions and is measured in bytes. A simple task needs fewer instructions than a complicated one. Sarah finds that her calculator is 10 MB, her camera 20 MB, and her messaging app 70 MB; together they use 100 MB.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['itf.software.types']::text[], 1, 'explanation', null)
