insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch3-l2-s2', 'itf-f-ch3-l2', 'itf-f-ch3-l2-milestone', 2, 'The operating system helps applications', 'discussion', 'teach', 'The operating system is system software: a set of programs that controls the computer and allows it to operate as a system. Two important tasks are operating the hardware and helping applications work as part of the system. Sarah''s messaging app knows how to read and type messages, but it must call the operating system to show a message on the screen or receive a touch from the digitizer. If every app carried all the operating system''s hardware instructions, apps would be much larger. Sarah''s operating system uses 20 GB of her 50 GB storage. Sharing that one operating system leaves 30 GB for applications, including her three apps that total 100 MB. The operating system also displays app icons and starts the app a user selects.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['itf.software.types']::text[], 1, 'explanation', null)
