insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch3-l2-s3', 'itf-f-ch3-l2', 'itf-f-ch3-l2-milestone', 3, 'Trace how the operating system starts an app', 'code', 'practice', 'Starting an app follows four ordered instructions in the book: accept the user''s input, search storage for the app, copy the app to memory, and allow the app to use the processor. Run this Jargon translation of the book''s generic APP sequence and check that the four lines appear in that order.', 'code', 'SET app ("APP")
PRINT "Accept user input"
PRINT "Search storage for " + app
PRINT "Copy " + app + " to memory"
