insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch3-l2-s4', 'itf-f-ch3-l2', 'itf-f-ch3-l2-milestone', 4, 'Firmware prepares the computer', 'discussion', 'teach', 'BIOS is firmware. It is the first program to run when a computer is powered on, tests the hardware, loads part of the operating system from storage to memory, and hands the operating system control of the processor. On Sarah''s smartphone, BIOS searches for connected devices; tests the digitizer, screen, microphone, speaker, camera, antennas, memory, and storage; ends the system test; finds the operating system; copies part of it to memory; and lets it take over. A shared BIOS device-test program can place a device name inside brackets. The main program calls that same test for the screen, keyboard, mouse, memory, and storage instead of keeping a separate test program for each device.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['itf.software.types']::text[], 1, 'explanation', null)
