insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch3-l2-s5', 'itf-f-ch3-l2', 'itf-f-ch3-l2-milestone', 5, 'Investigate software and design a BIOS test', 'discussion', 'practice', 'Investigate your computer as the book directs. Identify three applications and give each name, size, and task; name the storage device and its capacity; record the space used by the operating system and applications; and list the hardware parts. Then state two operating-system tasks, explain how it helps applications, and name the first program after power-on with its tasks. For a desktop with screen, keyboard, mouse, memory, and storage, write the ordered BIOS instructions that test those devices and load the operating system; use them for the Word file ''BIOS - My Desktop Computer,'' complete its OPEN line, apply the same font, numbering, and first-word formatting used earlier, and compare the formatting sequence with Activities 1.6 and 1.7. Finally substitute SCREEN and KEYBOARD into the shared device-test brackets, determine how many times the main program calls that test, list every tested device, and adapt the bracket list for a tablet with digitizer, screen, memory, and storage.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['itf.software.types', 'jargon.set']::text[], 1, 'practice', 'applied')
