insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch4-l1-s1', 'itf-f-ch4-l1', 'itf-f-ch4-l1-milestone', 1, 'Data, instructions, and files', 'discussion', 'intro', 'Data is any item of information. Instructions need data; without data, instructions cannot work. Data and instructions enter as input and remain in memory to be processed. In Example 1.1, Ms. Finn tells Sam to add 4 and 1: "Add" is the instruction, while 4 and 1 are the data. Example 1.2 follows both through Sam''s input, memory, processing, and written output of 5. In a computer, information that belongs together is grouped into a file, and all files are saved in storage. Some files are instruction files, such as apps; others are data files, such as images. In Example 1.3, Jenna''s Camera app contains the instructions needed to take a photo, while the photo file contains the data needed to make the image.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['itf.data.structures']::text[], 1, 'explanation', null)
on conflict (id) do update set
  lesson_id = excluded.lesson_id,
  milestone_id = excluded.milestone_id,
  position = excluded.position,
  title = excluded.title,
  activity_type = excluded.activity_type,
  stage = excluded.stage,
  prompt = excluded.prompt,
  response_mode = excluded.response_mode,
  starter_code = excluded.starter_code,
  expected_output = excluded.expected_output,
  choices = excluded.choices,
  rubric = excluded.rubric,
  skill_keys = excluded.skill_keys,
  pass_score = excluded.pass_score,
  mode = excluded.mode,
  mode_type = excluded.mode_type;

insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch4-l1-s2', 'itf-f-ch4-l1', 'itf-f-ch4-l1-milestone', 2, 'Lists and tables', 'discussion', 'teach', 'Inside a file, data is arranged according to structures. A list is a data structure in which data is arranged in a line, one item after the other. Each item is identified by its place number. In Example 1.4, Ms. Moore writes Omar, Maya, Lana, and Tom in a list; whether the line is vertical or horizontal, Omar is at Place 1 and Tom is at Place 4. A table is a data structure in which data is arranged in rows and columns, with each item in a cell identified by its row and column. In Example 1.5, Ms. Moore''s birthday table has four rows and two columns: Row 1, Column 1 contains Omar, while Row 3, Column 2 contains September 29.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['jargon.list', 'itf.data.structures']::text[], 1, 'explanation', null)
on conflict (id) do update set
  lesson_id = excluded.lesson_id,
  milestone_id = excluded.milestone_id,
  position = excluded.position,
  title = excluded.title,
  activity_type = excluded.activity_type,
  stage = excluded.stage,
  prompt = excluded.prompt,
  response_mode = excluded.response_mode,
  starter_code = excluded.starter_code,
  expected_output = excluded.expected_output,
  choices = excluded.choices,
  rubric = excluded.rubric,
  skill_keys = excluded.skill_keys,
  pass_score = excluded.pass_score,
  mode = excluded.mode,
  mode_type = excluded.mode_type;

insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch4-l1-s3', 'itf-f-ch4-l1', 'itf-f-ch4-l1-milestone', 3, 'Structures used by the computer', 'discussion', 'teach', 'Lists and tables are important to a computer''s operation. In Example 1.6, BIOS tests the mouse, keyboard, screen, microphone, speaker, memory, WiFi antenna, storage, and printer, then records each device and its OK or NOT OK status in a Device Status Table. The printer is initially NOT OK, so the operating system shows an error instead of printing. After Ms. Moore reconnects the printer, its status is updated to OK. The operating system also prepares device task lists: Files for Opening tells storage to open Section 6A, 6B, and 6C, while Files for Printing tells the printer which files to print. The names of devices and files are all data organized so the computer can use them.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['jargon.list', 'itf.data.structures']::text[], 1, 'explanation', null)
