PRINT animals', '[''apples'', ''oranges'', ''bananas'', ''kiwis'', ''mangos'']
[[''tigers'', 6], [''monkeys'', 17], [''giraffes'', 7], [''meerkats'', 23]]', '[]'::jsonb, '{}'::jsonb, ARRAY['jargon.list', 'itf.data.structures']::text[], 1, 'practice', 'code')
