values ('itf-f-ch4-l1-s6', 'itf-f-ch4-l1', 'itf-f-ch4-l1-milestone', 6, 'Check: data and structures', 'multiple_choice', 'assessment', 'Select every statement that is true.', 'multiple_choice', '', null, '[{"id": "a", "text": "Instructions need data."}, {"id": "b", "text": "In a computer, information that belongs together is grouped into files."}, {"id": "c", "text": "A list and a table are different data structures."}, {"id": "d", "text": "Data in a list is arranged in rows and columns."}, {"id": "e", "text": "A list contains data arranged in a line, one item after the other."}, {"id": "f", "text": "The operating system does not use lists and tables."}, {"id": "g", "text": "A device status table is a table prepared by BIOS."}, {"id": "h", "text": "A device task list is a list of tasks a device should perform."}]'::jsonb, '{}'::jsonb, ARRAY['itf.data.structures']::text[], 1, 'assessment', 'mcq')
