insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch4-l2-s1', 'itf-f-ch4-l2', 'itf-f-ch4-l2-milestone', 1, 'Where an instruction finds data', 'discussion', 'intro', 'Instructions need data. An instruction either has the data it needs or has an address pointing to where the data may be found. An address points to where a group of data or an item of data is located, and names identify groups such as lists, tables, and files. In Example 2.1, the words "Start" and "End" appear inside WRITE instructions; quotation marks identify them as data. Data can also be in the same instruction file without being part of the instruction. In Example 2.2, File: Terminator Boxes has List: A = {Start, End}. A READ instruction uses the address List: A / Place 1 to get Start and List: A / Place 2 to get End.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['jargon.set', 'itf.data.addressing']::text[], 1, 'explanation', null)
