insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch4-l2-s2', 'itf-f-ch4-l2', 'itf-f-ch4-l2-milestone', 2, 'Files inside folders', 'discussion', 'teach', 'Data required by an instruction may be in another file. In that case, the address must name the file and where it is found. Files that belong together are grouped into folders. In Example 2.3, Jenna''s Camera app opens the Images folder, creates a new file, writes the captured image data into it, names it Photo 20220929_1604, saves it, and closes it. Later, the Image Viewer app follows the address Folder: Images / File: Photo 20220929_1604, reads the image data, and prints the image to the screen. The folder name and file name let the app find the correct data file.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['itf.data.addressing']::text[], 1, 'explanation', null)
