insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch4-l2-s3', 'itf-f-ch4-l2', 'itf-f-ch4-l2-milestone', 3, 'Web addresses reach another computer', 'discussion', 'teach', 'Data may also be in another file on another computer. Then its address must identify the computer, folder, and file. The Internet is used to reach data on another computer, and a web address points to where that data may be found. In Example 2.4, Liam selects a YouTube video thumbnail. Hidden with the thumbnail is the web address of the video file on a YouTube server. The YouTube app follows that address, reads the video data, and plays the images and sounds on Liam''s smartphone. A web address therefore serves the same locating purpose across computers that file, list, place, row, and column names serve inside one computer.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['itf.data.addressing']::text[], 1, 'explanation', null)
