insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch4-l2-s4', 'itf-f-ch4-l2', 'itf-f-ch4-l2-milestone', 4, 'Read data by address', 'code', 'practice', 'Activities 2.2–2.4 build Farm and Zoo lists by reading data from named places. Jargon list indices begin at 0, so the book''s Place 2 is index 1. Run the program: it reads donkey from the second place in Extra, adds it to Farm, then reads the first, third, and fourth places into Zoo.', 'code', 'SET farm (["horse", "cow", "chicken"])
SET extra (["zebra", "donkey", "giraffe", "lion"])
SET item (extra[1])
ADD item to farm
SET zoo ([])
ADD extra[0] to zoo
ADD extra[2] to zoo
ADD extra[3] to zoo
PRINT farm
PRINT zoo', '[''horse'', ''cow'', ''chicken'', ''donkey'']
[''zebra'', ''giraffe'', ''lion'']', '[]'::jsonb, '{}'::jsonb, ARRAY['jargon.set', 'itf.data.addressing']::text[], 1, 'practice', 'code')
