insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch4-l2-s5', 'itf-f-ch4-l2', 'itf-f-ch4-l2-milestone', 5, 'Write complete addresses', 'discussion', 'practice', 'Write the full book-style address for each requested item. File Food has List Dairy = {milk, cheese, yogurt} and List Cereals = {rice, wheat, corn}. File Animals has List Farm = {horse, cow, chicken, donkey, duck, goat} and List Zoo = {zebra, giraffe, lion, meerkat, gorilla, monkey, gazelle, flamingo}. Folder Grade 6 / File Section 6A has List Boys = {Chen, Liam, Jon, Ahmed}; Grade 6 / Section 6B has List Girls = {Diana, Sarah, Maya, Deena}; Folder Grade 5 / File Section 5B has List Girls = {Maria, Ronda, Janice, Rachel}. Also, Folder Videos contains Video 1, Video 2, and Video 3. Give addresses for cheese, gorilla, rice, donkey, Ahmed, Maria, Sarah, and Video 2. Then, with teacher assistance, visit the book''s three web-address examples: https://pbskids.org, https://www.coolmath.com, and https://kids.nationalgeographic.com.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['itf.data.addressing']::text[], 1, 'practice', 'applied')
