insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch4-l3-s1', 'itf-f-ch4-l3', 'itf-f-ch4-l3-milestone', 1, 'Search one place at a time', 'discussion', 'intro', 'Searching for and finding data is an important task performed by computers. A list arranges data in a line, so one strategy is to start at the beginning and check each place in order. If the item is found, the search ends; otherwise, move to the next place. This is called a linear search. In Example 3.1, Ms. Moore searches the Trip List for Carl. At each place she reads a name and asks whether it is Carl. Donna, Anna, and Harvey do not match, so she moves on. At Place 4 she reads Carl, says "I found Carl!", and ends the search instead of checking Grace.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['itf.data.searching', 'jargon.loop']::text[], 1, 'explanation', null)
on conflict (id) do update set
  lesson_id = excluded.lesson_id,
