  mode = excluded.mode,
  mode_type = excluded.mode_type;

insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch4-l3-s2', 'itf-f-ch4-l3', 'itf-f-ch4-l3-milestone', 2, 'The two ways a search ends', 'discussion', 'teach', 'A linear search also needs a second stopping condition. In Example 3.2, Ms. Moore searches for Kim. She checks Donna, Anna, Harvey, Carl, Grace, Ahmed, and Lana. No name matches, so when she reaches the last name she says, "I did not find Kim," and ends. Example 3.3 extends the same process to a computer searching a list of 100 telephone numbers. The program goes to the first place, reads an item, checks whether it matches, checks whether the search has reached the end, and otherwise moves to the next place and repeats. Computers can use these instructions to search lists containing thousands of items.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['itf.data.searching', 'jargon.loop']::text[], 1, 'explanation', null)
on conflict (id) do update set
  lesson_id = excluded.lesson_id,
