insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch4-l3-s3', 'itf-f-ch4-l3', 'itf-f-ch4-l3-milestone', 3, 'Search the field-trip list', 'code', 'practice', 'Activity 3.2 asks for Maya in the Field Trip list. Run a linear search over the book''s names. The loop checks each name; because the list contains May but not Maya, the search reaches the end and prints the not-found message.', 'code', 'SET names (["Anne", "Dan", "Zena", "Ren", "Lin", "Jon", "Benjamin", "Chen", "Donna", "Harvey", "Loise", "Mike", "Kirk", "Lana", "Jenna", "Micha", "Sarah", "Liam", "Scot", "Tala", "Maria", "Susan", "Charlie", "Gabriel", "Thomas", "Matthew", "Ahmed", "Akira", "Chang", "Hana", "Choi", "Aya", "May", "Rosanne", "Rola", "Rana", "Samira", "Mona", "Hana", "Fares", "Tarek", "Chris", "Arnold", "Dora", "Dana", "Leya", "Karl", "Omar"])
SET target ("Maya")
SET found (False)
REPEAT_FOR_EACH name in names
    IF name is equal to target THEN
        PRINT "Found " + target
        SET found (True)
        BREAK
    END
END
IF found is equal to False THEN
    PRINT target + " is not in the list"
END', 'Maya is not in the list', '[]'::jsonb, '{}'::jsonb, ARRAY['itf.data.searching', 'jargon.loop']::text[], 1, 'practice', 'code')
