values ('itf-f-ch4-l3-s4', 'itf-f-ch4-l3', 'itf-f-ch4-l3-milestone', 4, 'Search the locker numbers', 'code', 'practice', 'Activity 3.3 asks whether locker 425 has been assigned. Locker numbers are kept as strings so leading zeros such as 034 and 002 remain part of their data. Run the linear search; it stops as soon as 425 is found.', 'code', 'SET numbers (["323", "379", "523", "100", "634", "544", "277", "331", "669", "412", "333", "102", "034", "011", "458", "512", "599", "367", "273", "732", "555", "486", "352", "123", "370", "563", "190", "684", "547", "247", "391", "663", "433", "312", "134", "002", "058", "417", "425", "592", "519", "327", "373", "552", "375", "406", "302", "300", "309", "223", "140", "614", "541", "257", "361", "699", "412", "353", "142", "434", "111"])
SET target ("425")
SET found (False)
REPEAT_FOR_EACH number in numbers
    IF number is equal to target THEN
        PRINT "Found " + target
        SET found (True)
        BREAK
    END
END
IF found is equal to False THEN
    PRINT target + " is not in the list"
END', 'Found 425', '[]'::jsonb, '{}'::jsonb, ARRAY['itf.data.searching', 'jargon.loop']::text[], 1, 'practice', 'code')
