values ('itf-f-ch4-l3-s5', 'itf-f-ch4-l3', 'itf-f-ch4-l3-milestone', 5, 'Check: linear search', 'multiple_choice', 'assessment', 'Select every statement that is true.', 'multiple_choice', '', null, '[{"id": "a", "text": "A list is a data structure arranged in the form of a line."}, {"id": "b", "text": "A linear search is a method for searching a list for a data item."}, {"id": "c", "text": "A computer does not need instructions to perform a linear search."}, {"id": "d", "text": "A linear search checks each place in a list one after the other."}, {"id": "e", "text": "A linear search should end when the data item is found."}, {"id": "f", "text": "A linear search should not end when it reaches the end of the list."}, {"id": "g", "text": "A linear search loops for every place in the list."}, {"id": "h", "text": "A linear search does not have any conditions to break the loop."}]'::jsonb, '{}'::jsonb, ARRAY['itf.data.searching', 'jargon.loop']::text[], 1, 'assessment', 'mcq')
