insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch4-l4-s2', 'itf-f-ch4-l4', 'itf-f-ch4-l4-milestone', 2, 'Compare, switch, and repeat', 'discussion', 'teach', 'Example 4.2 sorts Donna, Anna, Harvey, Carl, and Grace alphabetically. Compare each pair of consecutive items. Donna and Anna are out of order, so they switch. Donna and Harvey stay. Harvey and Carl switch; then Harvey and Grace switch. Reaching the end after making switches means another run is required. On the next run, Carl and Donna switch, while the other compared pairs stay. One last run makes no switches, so the sort ends with Anna, Carl, Donna, Grace, Harvey. The program therefore starts at the first place, compares two consecutive items, switches them only when they are out of order, moves one place, and starts again after the end whenever at least one switch occurred.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['itf.data.sorting']::text[], 1, 'explanation', null)
