insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch4-l5-s2', 'itf-f-ch4-l5', 'itf-f-ch4-l5-milestone', 2, 'Stacks are last in, first out', 'discussion', 'teach', 'A stack is another type of list. New items are added at the beginning or top, and items are also removed from that top. Items entering last therefore leave first: last in, first out. In Example 5.3, the last book placed on the librarian''s pile is on top and returns to the shelf first; the first book is at the bottom and returns last. The operating system uses stacks to reverse user actions. In Example 5.4, Mike types "This is my homework," changes the font size to 24, and then makes it bold. Undo first removes the last action, Bold, then Font Size 24, and then the last typed word at the top of the remaining action stack.', 'text', '', null, '[]'::jsonb, '{}'::jsonb, ARRAY['itf.data.stack', 'jargon.list']::text[], 1, 'explanation', null)
