insert into public.lesson_activities (id, lesson_id, milestone_id, position, title, activity_type, stage, prompt, response_mode, starter_code, expected_output, choices, rubric, skill_keys, pass_score, mode, mode_type)
values ('itf-f-ch4-l5-s3', 'itf-f-ch4-l5', 'itf-f-ch4-l5-milestone', 3, 'Update device-task queues', 'code', 'practice', 'Model Activity 5.2 with Jargon lists. ADD places a new task at a queue''s end. To complete the oldest task, read index 0 and REMOVE that value. The program follows Joe''s save, print, and upload events, prints the one remaining upload task, completes it, and confirms that all queues are empty.', 'code', 'SET save_queue (["Math Homework", "Science Project", "English Essay"])
SET print_queue (["English Essay"])
SET upload_queue ([])
SET front (save_queue[0])
REMOVE front from save_queue
ADD "Science Project" to print_queue
REPEAT 2 times
    SET front (save_queue[0])
    REMOVE front from save_queue
END
SET front (print_queue[0])
REMOVE front from print_queue
ADD "Math Homework" to upload_queue
ADD "Science Project" to upload_queue
SET front (print_queue[0])
REMOVE front from print_queue
SET front (upload_queue[0])
REMOVE front from upload_queue
PRINT upload_queue
SET front (upload_queue[0])
REMOVE front from upload_queue
PRINT save_queue
PRINT print_queue
PRINT upload_queue', '[''Science Project'']
[]
[]
[]', '[]'::jsonb, '{}'::jsonb, ARRAY['itf.data.queue', 'jargon.list']::text[], 1, 'practice', 'code')
