values ('itf-f-ch4-l5-s4', 'itf-f-ch4-l5', 'itf-f-ch4-l5-milestone', 4, 'Update an Undo stack', 'code', 'practice', 'Model Activity 5.3. Each word is one action, and punctuation stays with the word before it. In this Jargon list, the rightmost item is the stack''s top: each Undo reads the last item and removes it. The program applies Joe''s three Undos, adds his next five words, then applies four more Undos.', 'code', 'SET actions (["One", "sunny", "summer", "morning,", "I", "went"])
REPEAT 3 times
    SET top (actions[len(actions)-1])
    REMOVE top from actions
END
PRINT actions
ADD "evening," to actions
ADD "we" to actions
ADD "decided" to actions
ADD "to" to actions
ADD "go" to actions
REPEAT 4 times
    SET top (actions[len(actions)-1])
    REMOVE top from actions
END
PRINT actions', '[''One'', ''sunny'', ''summer'']
[''One'', ''sunny'', ''summer'', ''evening,'']', '[]'::jsonb, '{}'::jsonb, ARRAY['itf.data.stack', 'jargon.list']::text[], 1, 'practice', 'code')
